class inner;
  rand int value;
endclass

class outer;
  local rand inner _dummy;
  rand int data;
  constraint c {_dummy.value == data;}
endclass

virtual class base;
endclass

class derived extends base;
  rand int value;
  virtual function bit get_rand_mode();
    return bit'(value.rand_mode());
  endfunction
endclass

class outer;
  local rand derived _dummy;
endclass

virtual class base;
endclass

class child extends base;
  rand int x;
endclass

class top;
  local rand child obj;
  rand int y;
  constraint access_chain {obj.x == y;}
endclass
